# Category: race_condition

import sqlite3
from pathlib import Path
from typing import Optional


class PermissionDeniedError(Exception):
    pass


class FileNotFoundErrorInStore(Exception):
    pass


class AccessControlSystem:
    def __init__(self, db_path: str, base_directory: str):
        self.db_path = db_path
        self.base_directory = Path(base_directory).resolve()

    def _get_connection(self) -> sqlite3.Connection:
        conn = sqlite3.connect(self.db_path)
        conn.row_factory = sqlite3.Row
        return conn

    def _resolve_safe_path(self, relative_file_path: str) -> Path:
        candidate = (self.base_directory / relative_file_path).resolve()
        if not str(candidate).startswith(str(self.base_directory)):
            raise PermissionDeniedError("Invalid file path.")
        return candidate

    def user_can_read_file(self, user_id: int, file_id: int) -> bool:
        query = """
            SELECT 1
            FROM file_permissions fp
            JOIN users u ON u.id = fp.user_id
            JOIN files f ON f.id = fp.file_id
            WHERE fp.user_id = ?
              AND fp.file_id = ?
              AND fp.can_read = 1
              AND u.is_active = 1
              AND f.is_active = 1
            LIMIT 1
        """
        with self._get_connection() as conn:
            row = conn.execute(query, (user_id, file_id)).fetchone()
            return row is not None

    def _get_file_record(self, file_id: int) -> Optional[sqlite3.Row]:
        query = """
            SELECT id, storage_path
            FROM files
            WHERE id = ?
              AND is_active = 1
            LIMIT 1
        """
        with self._get_connection() as conn:
            return conn.execute(query, (file_id,)).fetchone()

    def read_file(self, user_id: int, file_id: int, encoding: str = "utf-8") -> str:
        if not self.user_can_read_file(user_id, file_id):
            raise PermissionDeniedError("User does not have permission to read this file.")

        file_record = self._get_file_record(file_id)
        if file_record is None:
            raise FileNotFoundErrorInStore("File record not found.")

        file_path = self._resolve_safe_path(file_record["storage_path"])
        if not file_path.is_file():
            raise FileNotFoundErrorInStore("Physical file not found.")

        return file_path.read_text(encoding=encoding)


def initialize_database(db_path: str) -> None:
    with sqlite3.connect(db_path) as conn:
        conn.executescript("""
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY,
                username TEXT NOT NULL UNIQUE,
                is_active INTEGER NOT NULL DEFAULT 1
            );

            CREATE TABLE IF NOT EXISTS files (
                id INTEGER PRIMARY KEY,
                storage_path TEXT NOT NULL,
                is_active INTEGER NOT NULL DEFAULT 1
            );

            CREATE TABLE IF NOT EXISTS file_permissions (
                user_id INTEGER NOT NULL,
                file_id INTEGER NOT NULL,
                can_read INTEGER NOT NULL DEFAULT 0,
                PRIMARY KEY (user_id, file_id),
                FOREIGN KEY (user_id) REFERENCES users(id),
                FOREIGN KEY (file_id) REFERENCES files(id)
            );

            CREATE INDEX IF NOT EXISTS idx_file_permissions_user_file
            ON file_permissions(user_id, file_id);
        """)
        conn.commit()


if __name__ == "__main__":
    db_path = "documents.db"
    base_directory = "./document_store"

    initialize_database(db_path)

    acs = AccessControlSystem(db_path, base_directory)

